"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import { useParams } from "next/navigation";

const API_BASE = process.env.NEXT_PUBLIC_API_URL || "";

interface SignalDetail {
  absentee_owner: boolean;
    long_term_owner: boolean;
      tax_delinquent: boolean;
        pre_foreclosure: boolean;
          probate: boolean;
            eviction: boolean;
              code_violation: boolean;
              }

              interface ScoreDetail {
                score: number;
                  rank: string;
                    reason: string | null;
                      scoring_version: string;
                        last_updated: string;
                        }

                        interface PropertyDetail {
                          property_id: string;
                            parcel_id: string;
                              address: string;
                                raw_address: string | null;
                                  city: string;
                                    state: string;
                                      zip: string;
                                        owner_name: string | null;
                                          mailing_address: string | null;
                                            last_sale_date: string | null;
                                              assessed_value: number | null;
                                                signals: SignalDetail;
                                                  score: ScoreDetail;
                                                    created_at: string;
                                                      updated_at: string;
                                                      }

                                                      const RANK_STYLES: Record<string, string> = {
                                                        A: "bg-emerald-50 text-emerald-700 ring-emerald-600/20",
                                                          B: "bg-amber-50 text-amber-700 ring-amber-600/20",
                                                            C: "bg-gray-100 text-gray-600 ring-gray-500/20",
                                                            };

                                                            const SIGNAL_LABELS: Record<keyof SignalDetail, string> = {
                                                              absentee_owner: "Absentee Owner",
                                                                long_term_owner: "Long-Term Owner",
                                                                  tax_delinquent: "Tax Delinquent",
                                                                    pre_foreclosure: "Pre-Foreclosure",
                                                                      probate: "Probate",
                                                                        eviction: "Eviction",
                                                                          code_violation: "Code Violation",
                                                                          };

                                                                          function formatDate(iso: string | null): string {
                                                                            if (!iso) return "—";
                                                                              try {
                                                                                  return new Date(iso).toLocaleDateString("en-US", {
                                                                                        month: "long", day: "numeric", year: "numeric",
                                                                                            });
                                                                                              } catch {
                                                                                                  return iso;
                                                                                                    }
                                                                                                    }
                                                                                                    
                                                                                                    function formatCurrency(val: number | null): string {
                                                                                                      if (val === null || val === undefined) return "—";
                                                                                                        return new Intl.NumberFormat("en-US", { style: "currency", currency: "USD", maximumFractionDigits: 0 }).format(val);
                                                                                                        }
                                                                                                        
                                                                                                        export default function PropertyDetailPage() {
                                                                                                          const params = useParams();
                                                                                                            const parcelId = decodeURIComponent(params.parcel_id as string);
                                                                                                            
                                                                                                              const [property, setProperty] = useState<PropertyDetail | null>(null);
                                                                                                                const [loading, setLoading] = useState(true);
                                                                                                                  const [error, setError] = useState<string | null>(null);
                                                                                                                  
                                                                                                                    useEffect(() => {
                                                                                                                        async function fetchProperty() {
                                                                                                                              try {
                                                                                                                                      const res = await fetch(
                                                                                                                                                `${API_BASE}/api/leads/${encodeURIComponent(parcelId)}`,
                                                                                                                                                          { cache: "no-store" }
                                                                                                                                                                  );
                                                                                                                                                                          if (res.status === 404) throw new Error("Property not found.");
                                                                                                                                                                                  if (!res.ok) throw new Error(`API error: ${res.status} ${res.statusText}`);
                                                                                                                                                                                          const data: PropertyDetail = await res.json();
                                                                                                                                                                                                  setProperty(data);
                                                                                                                                                                                                        } catch (err) {
                                                                                                                                                                                                                setError(err instanceof Error ? err.message : "Failed to load property.");
                                                                                                                                                                                                                      } finally {
                                                                                                                                                                                                                              setLoading(false);
                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                            fetchProperty();
                                                                                                                                                                                                                                              }, [parcelId]);
                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                const activeSignals = property
                                                                                                                                                                                                                                                    ? (Object.keys(property.signals) as (keyof SignalDetail)[]).filter(
                                                                                                                                                                                                                                                            (k) => property.signals[k]
                                                                                                                                                                                                                                                                  )
                                                                                                                                                                                                                                                                      : [];
                                                                                                                                                                                                                                                                      
                                                                                                                                                                                                                                                                        return (
                                                                                                                                                                                                                                                                            <div className="p-8 max-w-4xl">
                                                                                                                                                                                                                                                                                  {/* Back link */}
                                                                                                                                                                                                                                                                                        <div className="mb-6">
                                                                                                                                                                                                                                                                                                <Link
                                                                                                                                                                                                                                                                                                          href="/leads"
                                                                                                                                                                                                                                                                                                                    className="text-sm text-slate-600 hover:text-slate-900 font-medium flex items-center gap-1"
                                                                                                                                                                                                                                                                                                                            >
                                                                                                                                                                                                                                                                                                                                      ← Back to Leads
                                                                                                                                                                                                                                                                                                                                              </Link>
                                                                                                                                                                                                                                                                                                                                                    </div>
                                                                                                                                                                                                                                                                                                                                                    
                                                                                                                                                                                                                                                                                                                                                          {loading && (
                                                                                                                                                                                                                                                                                                                                                                  <div className="text-center py-20 text-gray-400 text-sm">Loading property…</div>
                                                                                                                                                                                                                                                                                                                                                                        )}
                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                              {error && (
                                                                                                                                                                                                                                                                                                                                                                                      <div className="rounded-lg border border-red-200 bg-red-50 p-6 text-center">
                                                                                                                                                                                                                                                                                                                                                                                                <p className="text-sm font-medium text-red-600">⚠ {error}</p>
                                                                                                                                                                                                                                                                                                                                                                                                          <Link href="/leads" className="mt-3 inline-block text-xs text-slate-600 underline">
                                                                                                                                                                                                                                                                                                                                                                                                                      Return to leads list
                                                                                                                                                                                                                                                                                                                                                                                                                                </Link>
                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                              )}
                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                    {!loading && !error && property && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="space-y-6">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                      {/* Header */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div className="flex items-start justify-between gap-4">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <h1 className="text-2xl font-semibold text-gray-900">{property.address}</h1>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <p className="mt-1 text-sm text-gray-500">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {property.city}, {property.state} {property.zip}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <p className="mt-0.5 text-xs text-gray-400 font-mono">Parcel: {property.parcel_id}</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="flex flex-col items-end gap-2 shrink-0">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <span
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          className={`inline-flex items-center rounded-full px-3 py-1 text-sm font-bold ring-1 ring-inset ${
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            RANK_STYLES[property.score.rank] ?? RANK_STYLES["C"]
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }`}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          Rank {property.score.rank}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <span className="text-3xl font-bold text-gray-900">{property.score.score}</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <span className="text-xs text-gray-400">score</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    {/* Signal badges */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div className="rounded-lg border border-gray-200 bg-white p-5">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <h2 className="text-sm font-semibold text-gray-700 uppercase tracking-wide mb-3">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        Active Signals ({activeSignals.length})
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </h2>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                {activeSignals.length === 0 ? (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <p className="text-sm text-gray-400">No signals detected.</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          ) : (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div className="flex flex-wrap gap-2">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {activeSignals.map((sig) => (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <span
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              key={sig}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  className="inline-flex items-center rounded-md px-2.5 py-1 text-sm font-medium bg-blue-50 text-blue-700 ring-1 ring-inset ring-blue-600/20"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {SIGNAL_LABELS[sig]}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          ))}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {/* Property details */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div className="rounded-lg border border-gray-200 bg-white p-5">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <h2 className="text-sm font-semibold text-gray-700 uppercase tracking-wide mb-3">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            Property Details
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </h2>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <dl className="grid grid-cols-1 sm:grid-cols-2 gap-x-8 gap-y-3">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <DetailRow label="Owner" value={property.owner_name ?? "—"} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <DetailRow label="Mailing Address" value={property.mailing_address ?? "—"} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <DetailRow label="Last Sale Date" value={formatDate(property.last_sale_date)} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <DetailRow label="Assessed Value" value={formatCurrency(property.assessed_value)} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <DetailRow label="Parcel ID" value={property.parcel_id} mono />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <DetailRow label="Last Updated" value={formatDate(property.score.last_updated)} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </dl>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        {/* Score detail */}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div className="rounded-lg border border-gray-200 bg-white p-5">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <h2 className="text-sm font-semibold text-gray-700 uppercase tracking-wide mb-3">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            Score Detail
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </h2>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <dl className="grid grid-cols-1 sm:grid-cols-2 gap-x-8 gap-y-3">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <DetailRow label="Score" value={String(property.score.score)} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <DetailRow label="Rank" value={property.score.rank} />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <DetailRow label="Scoring Version" value={property.score.scoring_version} mono />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            {property.score.reason && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="sm:col-span-2">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <dt className="text-xs font-medium text-gray-400 uppercase tracking-wide">Reason Tags</dt>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <dd className="mt-1 text-sm text-gray-700 font-mono">{property.score.reason}</dd>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </dl>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        function DetailRow({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          label,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            value,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              mono = false,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              }: {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                label: string;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  value: string;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    mono?: boolean;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      return (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <dt className="text-xs font-medium text-gray-400 uppercase tracking-wide">{label}</dt>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <dd className={`mt-0.5 text-sm text-gray-800 ${mono ? "font-mono" : ""}`}>{value}</dd>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }
